code = """import json
import os

# Load the data files
capital_market_file = locals()['var_functions.query_db:20']
tables_file = locals()['var_functions.list_db:10']

with open(capital_market_file, 'r') as f:
    capital_market_data = json.load(f)

with open(tables_file, 'r') as f:
    all_tables = json.load(f)

# Create symbol to company name mapping
symbol_to_company = {}
for item in capital_market_data:
    symbol = item['Symbol']
    company_desc = item['Company Description']
    # Extract the company name (text before first period)
    company_name = company_desc.split('.')[0]
    symbol_to_company[symbol] = company_name

# Get symbols that have price data
available_symbols = set(all_tables)
valid_symbols = [symbol for symbol in symbol_to_company.keys() if symbol in available_symbols]

print('__RESULT__:')
print(json.dumps({
    'total_symbols': len(valid_symbols),
    'sample_symbols': valid_symbols[:10]
}))"""

